40	// Runs is the resolver for the runs field.
41	func (r *queryResolver) Runs(ctx context.Context, projectID *string, layer *RunLayer, beadID *string, status *string, harness *string, first *int, after *string) (*RunConnection, error) {
42		provider, ok := r.State.(RunsStateProvider)
43		if !ok {
44			return emptyRunConnection(), nil
45		}
46		pid := ""
47		if projectID != nil {
48			pid = *projectID
49		}
50		filter := RunFilter{Layer: layer}
51		if beadID != nil {
52			filter.BeadID = *beadID
53		}
54		if status != nil {
55			filter.Status = *status
56		}
57		if harness != nil {
58			filter.Harness = *harness
59		}
60		all := provider.GetRunsGraphQL(pid, filter)
61		return runConnectionFrom(all, first, after), nil
62	}
