64	// Run is the resolver for the run field.
65	func (r *queryResolver) Run(ctx context.Context, id string) (*Run, error) {
66		provider, ok := r.State.(RunsStateProvider)
67		if !ok {
68			return nil, nil
69		}
70		wd := r.workingDir(ctx)
71		if wd == "" {
72			return nil, nil
73		}
74		projectID, ok := r.projectIDForWorkingDir(wd)
75		if !ok {
76			return nil, nil
77		}
78		run, ok := provider.GetRunGraphQL(id)
79		if !ok {
80			return nil, nil
81		}
82		if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) != projectID {
83			return nil, nil
84		}
85		r.recordRunDetailView(ctx, run)
86		if runHasRawTranscriptSelection(ctx) {
87			r.recordRawTranscriptViewed(ctx, run)
88		}
89		return run, nil
90	}
