92	func (r *queryResolver) projectIDForWorkingDir(workingDir string) (string, bool) {
93		if r.State == nil || workingDir == "" {
94			return "", false
95		}
96		for _, proj := range r.State.GetProjectSnapshots(false) {
97			if proj.Path == workingDir {
98				return proj.ID, true
99			}
100		}
101		return "", false
102	}
