104	// recordRunDetailView appends the canonical run_detail_view bead audit event
105	// the first time a project-scoped run detail is resolved for a specific run.
106	// Duplicate loads of the same run id are ignored, but distinct runs on the
107	// same bead remain auditable.
108	func (r *queryResolver) recordRunDetailView(ctx context.Context, run *Run) {
109		if run == nil || run.BeadID == nil || strings.TrimSpace(*run.BeadID) == "" {
110			return
111		}
112		if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) == "" {
113			return
114		}
115		wd := r.workingDir(ctx)
116		if wd == "" {
117			return
118		}
119		if projectID, ok := r.projectIDForWorkingDir(wd); !ok || projectID != strings.TrimSpace(*run.ProjectID) {
120			return
121		}
122	
123		store := projectBeadStore(wd)
124		if existing, err := store.EventsByKind(*run.BeadID, runDetailViewEventKind); err == nil {
125			for _, ev := range existing {
126				if strings.Contains(ev.Body, "run_id="+run.ID) {
127					return
128				}
129			}
130		}
131	
132		identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
133		if httpReq := httpRequestFromContext(ctx); httpReq != nil {
134			identity = operatorPromptIdentity(httpReq)
135		}
136		body := fmt.Sprintf(
137			"project_id=%s run_id=%s layer=%s visibility=project_membership",
138			*run.ProjectID,
139			run.ID,
140			run.Layer,
141		)
142		_ = store.AppendEvent(*run.BeadID, bead.BeadEvent{
143			Kind:    runDetailViewEventKind,
144			Summary: "run detail viewed",
145			Body:    body,
146			Actor:   identity.actor,
147			Source:  "graphql:run",
148		})
149	}
