151	func runHasRawTranscriptSelection(ctx context.Context) bool {
152		if !gqlgraphql.HasOperationContext(ctx) {
153			return false
154		}
155		for _, field := range gqlgraphql.CollectAllFields(ctx) {
156			switch field {
157			case "prompt", "response", "stderr":
158				return true
159			}
160		}
161		return false
162	}
163	
164	func rawTranscriptSelectionSummary(ctx context.Context) string {
165		if !gqlgraphql.HasOperationContext(ctx) {
166			return ""
167		}
168		selected := gqlgraphql.CollectAllFields(ctx)
169		ordered := make([]string, 0, 3)
170		for _, name := range []string{"prompt", "response", "stderr"} {
171			for _, field := range selected {
172				if field == name {
173					ordered = append(ordered, name)
174					break
175				}
176			}
177		}
178		return strings.Join(ordered, ",")
179	}
