228	// RunToolCalls is the resolver for the runToolCalls field. Returns the
229	// normalized tool-call entries persisted at drain time, paginated by
230	// sequence. Returns an empty connection (not an error) for unknown ids or
231	// when the backing state provider does not implement RunDetailStateProvider.
232	func (r *queryResolver) RunToolCalls(ctx context.Context, id string, first *int, after *string) (*RunToolCallConnection, error) {
