260	func runToolCallConnectionFrom(calls []*RunToolCall, first *int, after *string) *RunToolCallConnection {
261		all := make([]*RunToolCallEdge, len(calls))
262		ids := make([]string, len(calls))
263		for i, c := range calls {
264			all[i] = &RunToolCallEdge{Node: c, Cursor: encodeStableCursor(c.ID)}
265			ids[i] = c.ID
266		}
267		startIdx, _ := stablePageBounds(ids, after, nil)
268		slice := all[startIdx:]
269		truncByFirst := false
270		if first != nil && *first >= 0 && *first < len(slice) {
271			slice = slice[:*first]
272			truncByFirst = true
273		}
274		pageInfo := &PageInfo{
275			HasPreviousPage: startIdx > 0,
276			HasNextPage:     truncByFirst,
277		}
278		if len(slice) > 0 {
279			pageInfo.StartCursor = &slice[0].Cursor
280			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
281		}
282		return &RunToolCallConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
283	}
