314	// ApplyRunFilter applies the filter to a list of runs. Exported so state_runs.go can call it.
315	func ApplyRunFilter(in []*Run, filter RunFilter) []*Run {
316		return applyRunFilter(in, filter)
317	}
318	
319	// applyRunFilter applies the filter to a list of runs.
320	func applyRunFilter(in []*Run, filter RunFilter) []*Run {
321		if len(in) == 0 {
322			return in
323		}
324		if filter.Layer == nil && filter.BeadID == "" && filter.Status == "" && filter.Harness == "" {
325			return in
326		}
327		out := in[:0:0]
328		for _, r := range in {
329			if filter.Layer != nil && r.Layer != *filter.Layer {
330				continue
331			}
332			if filter.BeadID != "" {
333				if r.BeadID == nil || *r.BeadID != filter.BeadID {
334					continue
335				}
336			}
337			if filter.Status != "" {
338				if !strings.EqualFold(r.Status, filter.Status) {
339					continue
340				}
341			}
342			if filter.Harness != "" {
343				if r.Harness == nil || *r.Harness != filter.Harness {
344					continue
345				}
346			}
347			out = append(out, r)
348		}
349		return out
350	}
