50	// makeRun creates a Run fixture for the given layer.
51	func makeRun(id string, layer ddxgraphql.RunLayer, status string) *ddxgraphql.Run {
52		now := time.Now().UTC().Format(time.RFC3339)
53		run := &ddxgraphql.Run{
54			ID:          id,
55			Layer:       layer,
56			Status:      status,
57			StartedAt:   &now,
58			ChildRunIds: []string{},
59		}
60		switch layer {
61		case ddxgraphql.RunLayerWork:
62			qi := `{"beads":["ddx-001","ddx-002"]}`
63			sc := "drain-all"
64			run.QueueInputs = &qi
65			run.StopCondition = &sc
66			run.SelectedBeadIds = []string{"ddx-001", "ddx-002"}
67			child1 := "try-001"
68			run.ChildRunIds = []string{child1}
69		case ddxgraphql.RunLayerTry:
70			bead := "ddx-001"
71			base := "abc123"
72			result := "def456"
73			wt := ".ddx/worktrees/try-001"
74			mo := "merged"
75			run.BeadID = &bead
76			run.BaseRevision = &base
77			run.ResultRevision = &result
78			run.WorktreePath = &wt
79			run.MergeOutcome = &mo
80			parent := "work-001"
81			run.ParentRunID = &parent
82			child1 := "run-001"
83			run.ChildRunIds = []string{child1}
84		case ddxgraphql.RunLayerRun:
85			bead := "ddx-001"
86			harness := "claude"
87			provider := "anthropic"
88			model := "claude-sonnet-4-6"
89			in := 1000
90			out := 500
91			dur := 12000
92			cost := 0.015
93			excerpt := "Task completed successfully."
94			run.BeadID = &bead
95			run.Harness = &harness
96			run.Provider = &provider
97			run.Model = &model
98			run.TokensIn = &in
99			run.TokensOut = &out
100			run.DurationMs = &dur
101			run.CostUsd = &cost
102			run.OutputExcerpt = &excerpt
103			run.EvidenceLinks = []string{".ddx/executions/20260501T010000-aabbccdd"}
104			parent := "try-001"
105			run.ParentRunID = &parent
106		}
107		return run
