110	// TestIntegration_Query_Runs covers list, layer filter, detail, and parent/child paths.
111	func TestIntegration_Query_Runs(t *testing.T) {
112		workDir, store := setupIntegrationDir(t)
113		base := newTestStateProvider(workDir, store)
114		projID := base.projects[0].ID
115		if err := store.Create(&bead.Bead{ID: "ddx-001", Title: "Run detail audit target", Status: bead.StatusOpen}); err != nil {
