477	// TestRunFilter_LayerFilter covers applyRunFilter edge cases.
478	func TestRunFilter_LayerFilter(t *testing.T) {
479		work := ddxgraphql.RunLayerWork
480		try := ddxgraphql.RunLayerTry
481		run := ddxgraphql.RunLayerRun
482	
483		runs := []*ddxgraphql.Run{
484			makeRun("work-001", ddxgraphql.RunLayerWork, "success"),
485			makeRun("try-001", ddxgraphql.RunLayerTry, "success"),
486			makeRun("run-001", ddxgraphql.RunLayerRun, "success"),
487			makeRunWithHarness("run-002", ddxgraphql.RunLayerRun, "failure", "codex"),
488		}
489	
490		cases := []struct {
491			name    string
492			filter  ddxgraphql.RunFilter
493			wantLen int
494			wantIDs []string
495		}{
496			{"no filter", ddxgraphql.RunFilter{}, 4, nil},
497			{"layer=work", ddxgraphql.RunFilter{Layer: &work}, 1, []string{"work-001"}},
498			{"layer=try", ddxgraphql.RunFilter{Layer: &try}, 1, []string{"try-001"}},
499			{"layer=run", ddxgraphql.RunFilter{Layer: &run}, 2, nil},
500			{"status=failure", ddxgraphql.RunFilter{Status: "failure"}, 1, []string{"run-002"}},
501			{"status=success", ddxgraphql.RunFilter{Status: "success"}, 3, nil},
502			{"harness=claude", ddxgraphql.RunFilter{Harness: "claude"}, 1, []string{"run-001"}},
503		}
504	
505		for _, tc := range cases {
506			t.Run(tc.name, func(t *testing.T) {
507				got := ddxgraphql.ApplyRunFilter(runs, tc.filter)
508				if len(got) != tc.wantLen {
509					t.Fatalf("filter %q: expected %d runs, got %d", tc.name, tc.wantLen, len(got))
510				}
511				for _, wantID := range tc.wantIDs {
512					found := false
513					for _, r := range got {
514						if r.ID == wantID {
515							found = true
516							break
517						}
518					}
519					if !found {
520						t.Fatalf("filter %q: expected run %q in result", tc.name, wantID)
521					}
522				}
523			})
524		}
525	}
